1	import express from 'express';
2	import cors from 'cors';
3	import { fileURLToPath } from 'node:url';
4	import { resolve, dirname, join } from 'node:path';
5	import commentsRouter from './api/comments.js';
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	
9	function createApp() {
10	  const app = express();
11	  const isProduction = process.env.NODE_ENV === 'production';
12	
13	  // ── Middleware ────────────────────────────────────────────────────────────
14	  // NOTE: origin:'*' + credentials:true is invalid per CORS spec (browsers reject it).
15	  // Use origin:true (reflect request Origin) in dev so credentials can coexist if needed.
16	  app.use(cors({
17	    origin: isProduction ? false : true, // 'true' reflects the request's Origin header
18	    credentials: true,
19	  }));
20	  app.use(express.json());
21	
22	  // ── API Routes ────────────────────────────────────────────────────────────
23	  app.use('/api', commentsRouter);
24	
25	  // ── Routes ────────────────────────────────────────────────────────────────
26	  app.get('/health', (_req, res) => res.json({ ok: true }));
27	
28	  // Dev/test-only routes (not in production)
29	  if (!isProduction) {
30	    app.post('/dev/echo', (req, res) => res.json(req.body));
31	    app.get('/dev/error', (req, res, next) => {
32	      const err = new Error('Test error');
33	      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
34	      next(err);
35	    });
36	  }
37	
38	  // ── Static files (production) ─────────────────────────────────────────────
39	  if (isProduction) {
40	    const distPath = join(__dirname, '..', 'client', 'dist');
41	    app.use(express.static(distPath));
42	    app.get('*', (_req, res) =>
43	      res.sendFile(join(distPath, 'index.html'))
44	    );
45	  }
46	
47	  // ── 404 handler ───────────────────────────────────────────────────────────
48	  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
49	
50	  // ── Error handler ─────────────────────────────────────────────────────────
51	  // eslint-disable-next-line no-unused-vars
52	  app.use((err, _req, res, _next) => {
53	    const status = err.status || err.statusCode || 500;
54	    res.status(status).json({ error: err.message || 'Internal Server Error' });
55	  });
56	
57	  return app;
58	}
59	
60	// Start when run as the entry point
61	// resolve() normalises relative paths before comparing
62	if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
63	  const app = createApp();
64	  const PORT = process.env.PORT || 3001;
65	  app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
66	}
67	
68	export { createApp };
