import { WebSocketServer } from 'ws';

// WebSocket.OPEN = 1 (numeric constant — avoids importing the WebSocket class)
const WS_OPEN = 1;

let wss = null;
let clients = new Set();
let heartbeatInterval = null;

function initWs(httpServer, { pingInterval = 30000 } = {}) {
  // Defensive: clear any existing state from a previous call
  if (heartbeatInterval) {
    clearInterval(heartbeatInterval);
    heartbeatInterval = null;
  }
  clients = new Set();

  wss = new WebSocketServer({ server: httpServer });

  wss.on('connection', (ws) => {
    ws.isAlive = true;
    clients.add(ws);

    ws.on('close', () => { clients.delete(ws); });
    ws.on('error', () => { clients.delete(ws); });
  });
}

// Stub — full implementation added in Subtask 2
function broadcast() {}

// closeWs: exported for test teardown; terminates all open connections so
// wss.close() doesn't hang waiting for them to drain naturally.
async function closeWs() {
  clearInterval(heartbeatInterval);
  heartbeatInterval = null;
  for (const client of clients) {
    client.terminate();
  }
  clients = new Set();
  if (wss) {
    await new Promise((resolve) => wss.close(resolve));
    wss = null;
  }
}

export { initWs, broadcast, closeWs };
```

