describe('Heartbeat / ping mechanism', () => {
  let httpServer, wsUrl;

  before(async () => {
    ({ httpServer, wsUrl } = await startWsServer({ pingInterval: 50 }));
  });

  after(async () => {
    await stopWsServer(httpServer);
