    // Connect 3 clients, destroy 1, assert exactly 2 receive the broadcast
    const [c1, c2, cDead] = await Promise.all([
      connectClient(wsUrl),
      connectClient(wsUrl),
      connectClient(wsUrl),
    ]);
    cDead._socket.destroy();
    await new Promise((resolve) => setTimeout(resolve, 100));

    // Set up listeners on the 2 alive clients BEFORE broadcasting
    const p1 = waitForMessage(c1);
