### Green: Add heartbeat to `server/ws/broadcaster.js`

Inside `initWs`, after `wss.on('connection', ...)`, add the pong listener inside the connection handler and the heartbeat interval:

```js
function initWs(httpServer, { pingInterval = 30000 } = {}) {
  if (heartbeatInterval) {
    clearInterval(heartbeatInterval);
    heartbeatInterval = null;
  }
  clients = new Set();

  wss = new WebSocketServer({ server: httpServer });

  wss.on('connection', (ws) => {
    ws.isAlive = true;
    clients.add(ws);

    ws.on('pong', () => { ws.isAlive = true; });   // ← ADD this line
    ws.on('close', () => { clients.delete(ws); });
    ws.on('error', () => { clients.delete(ws); });
  });

  // ── Heartbeat ─────────────────────────────────────────────────────────────
  heartbeatInterval = setInterval(() => {
    for (const client of clients) {
      if (!client.isAlive) {
        clients.delete(client);
        client.terminate();
      } else {
        client.isAlive = false;
        client.ping();
      }
    }
  }, pingInterval);

  wss.on('close', () => {
    clearInterval(heartbeatInterval);
    heartbeatInterval = null;
  });
}
```

Run `npm test` — all Subtask 1 + 2 + 3 tests pass (GREEN ✓).

**Note on Set iteration safety**: `for (const client of clients)` with `clients.delete(client)` inside the loop is safe in JavaScript — the Set iterator will not visit already-processed entries, and deleting the current entry does not affect future iterations.

