24	
25	function connectClient(wsUrl) {
26	  return new Promise((resolve, reject) => {
27	    const ws = new WebSocket(wsUrl);
28	    ws.once('open', () => resolve(ws));
29	    ws.once('error', reject);
30	  });
31	}
32	
33	function waitForMessage(ws) {
34	  return new Promise((resolve) => {
35	    ws.once('message', (data) => resolve(JSON.parse(data.toString())));
36	  });
37	}
38	
39	function closeClient(ws) {
40	  return new Promise((resolve) => {
41	    if (ws.readyState === WebSocket.CLOSED) return resolve();
42	    ws.once('close', resolve);
43	    ws.close();
44	  });
45	}
46	
47	function withTimeout(promise, ms) {
48	  return Promise.race([
49	    promise,
50	    new Promise((_, reject) =>
51	      setTimeout(() => reject(new Error(`Timed out after ${ms}ms`)), ms)
52	    ),
53	  ]);
54	}
